def create_opensearch_index(
    client,
    index_name: str,
    dimension: int = 768
):
    """Create OpenSearch index with k-NN"""
    
    index_body = {
        "settings": {
            "index": {
                "knn": True,
                "knn.algo_param.ef_search": 100,
                "number_of_shards": 2,
                "number_of_replicas": 1
            }
        },
        "mappings": {
            "properties": {
                "embedding": {
                    "type": "knn_vector",
                    "dimension": dimension,
                    "method": {
                        "name": "hnsw",
                        "space_type": "cosinesimil",
                        "engine": "nmslib",
                        "parameters": {
                            "ef_construction": 128,
                            "m": 16
                        }
                    }
                },
                "text": {
                    "type": "text",
                    "analyzer": "standard"
                },
                "source": {
                    "type": "keyword"
                },
                "metadata": {
                    "type": "object",
                    "enabled": True
                },
                "timestamp": {
                    "type": "date"
                }
            }
        }
    }
    
    if not client.indices.exists(index=index_name):
        client.indices.create(
            index=index_name,
            body=index_body
        )
        logger.info(f"Created index: {index_name}")
    else:
        logger.info(f"Index already exists: {index_name}")

        
def hybrid_search_opensearch(
    client,
    index_name: str,
    embeddings_client,
    query: str,
    top_k: int = 5,
    vector_weight: float = 0.7,
    keyword_weight: float = 0.3,
    filters: Dict = None
):
    """Hybrid search in OpenSearch"""
    
    # Generate query embedding
    query_vector = embeddings_client.embed_query(query)
    
    # Build search query
    search_body = {
        "size": top_k,
        "query": {
            "bool": {
                "should": [
                    {
                        "knn": {
                            "embedding": {
                                "vector": query_vector,
                                "k": top_k
                            }
                        }
                    },
                    {
                        "match": {
                            "text": {
                                "query": query,
                                "boost": keyword_weight / vector_weight
                            }
                        }
                    }
                ]
            }
        }
    }
    
    # Add filters
    if filters:
        search_body["query"]["bool"]["filter"] = [
            {"term": {key: value}}
            for key, value in filters.items()
        ]
    
    # Execute search
    response = client.search(
        index=index_name,
        body=search_body
    )
    
    # Format results
    results = []
    for hit in response["hits"]["hits"]:
        results.append({
            "id": hit["_id"],
            "text": hit["_source"]["text"],
            "source": hit["_source"]["source"],
            "metadata": hit["_source"]["metadata"],
            "score": hit["_score"]
        })
    
    return results
